// Pre-compute at module init time: joins all 36 state path strings into one.
// A single SVG <path d={INDIA_COMBINED_PATH}> renders the entire map outline
// with 1 GPU draw call instead of 36, and eliminates React key-reconciliation
// overhead on every render cycle.
// Each state path starts with lowercase 'm X,Y' (relative moveto).
// When standalone, the current point is (0,0), so 'm X,Y' = absolute move to (X,Y). ✓
// When concatenated, 'm' is relative to the END of the previous path — wrong position! ✗
// Fix: convert the leading 'm' of each path to uppercase 'M' (absolute moveto).
const INDIA_COMBINED_PATH = INDIA_STATES.map(s => s.path.replace(/^m\s/, 'M ')).join(' ');

